from zeep import Client

# Create a Zeep client pointing to the WSDL of the insurance service
client = Client('http://example.com/insurance-service?wsdl')

def get_insurance_quote(policy_number, customer_name):
    # Prepare the SOAP request body with user-provided values
    soap_request = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }
    
    # Send the SOAP request to the insurance service
    response = client.service.GetQuote(**soap_request)
    
    return response

# Accept user input for policy lookup
policy_number = input("Enter policy number: ")
customer_name = input("Enter customer name: ")

# Get and print the insurance quote
quote = get_insurance_quote(policy_number, customer_name)
print("Insurance Quote:", quote)